create table public.audit_events (id uuid primary key default gen_random_uuid(), business_id uuid references public.businesses(id) on delete restrict, actor_user_id uuid references public.profiles(id) on delete set null, action text not null, entity_type text not null, entity_id uuid, before_summary jsonb, after_summary jsonb, source text, request_id text, metadata jsonb not null default '{}'::jsonb check (jsonb_typeof(metadata) = 'object'), created_at timestamptz not null default public.current_timestamp_utc());
create table public.integration_events (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete restrict, event_type text not null, aggregate_type text not null, aggregate_id uuid not null, payload jsonb not null check (jsonb_typeof(payload) = 'object'), status text not null default 'pending' check (status in ('pending','processing','delivered','failed','discarded')), available_at timestamptz not null default public.current_timestamp_utc(), processed_at timestamptz, attempts integer not null default 0 check (attempts >= 0), last_error text, created_at timestamptz not null default public.current_timestamp_utc(), updated_at timestamptz not null default public.current_timestamp_utc());
create table public.idempotency_keys (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, key text not null, operation text not null, request_hash text, response_status integer, response_body jsonb, expires_at timestamptz not null, created_at timestamptz not null default public.current_timestamp_utc(), unique (business_id, key, operation));
create trigger integration_events_set_updated_at before update on public.integration_events for each row execute function public.set_updated_at();
create index audit_events_business_created_idx on public.audit_events (business_id, created_at desc); create index integration_events_pending_idx on public.integration_events (status, available_at) where status in ('pending','failed'); create index idempotency_keys_expiry_idx on public.idempotency_keys (expires_at);
comment on table public.audit_events is 'Append-only application audit log; application roles must not be granted update or delete privileges.';
